/// <summary>
/// Data contract class for ZeroRatedSalesReport
/// </summary>
[DataContractAttribute,
SysOperationContractProcessing(classStr(ETGZeroRatedSalesReportUIBuilder))]
internal final class ETGZeroRatedSalesReportContract implements SysOperationValidatable
{
    FromDate            fromDate;
    ToDate              toDate;
    List                custAccount;
    ETGBusinessSegment  etgBusinessSegment;
    ETGConnectionType   etgConnectionType;
    List                invoiceId;

}

