/// Gets and sets the value of the datacontract parameter InvoiceId
/// </summary>
/// <param name = "_invoiceId">InvoiceId</param>
/// <returns>The current value of datacontract parameter InvoiceId</returns>
[
    DataMemberAttribute, AifCollectionType('InvoiceNumber', Types::String),
    SysOperationLabelAttribute(literalStr("@ETG_New:InvoiceNumber")),
